var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"미안하지만 나한테 그런 시시한 총알은 안 박힌다고!","JPN":"悪いけど、オレに弾丸なんてものは効かねえ！","ENG":"Sorry, but those bullets won't work on me!","TWN":"不好意思，用那些子彈可打不中我！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"닥쳐! 당장 그만두라고! 대체 이게 무슨 짓이야!","JPN":"黙って！　今すぐやめなさい！　何の真似ですか！","ENG":"Shut up! Stop what you're doing right now! What's the meaning of this?!","TWN":"閉嘴！馬上給我停下來！你到底在幹什麼！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"오호, 소령과 다르게 이쪽은 제법 공격이 날카로운데? 받아 칠 맛이 나겠어.","JPN":"へえ、少佐と違って、こっちの攻撃は結構鋭いな？　打ち返し甲斐がある。","ENG":"Oh? Your attacks are quite threatening, unlike Major's. This is gonna be fun.","TWN":"哇喔，這邊的攻擊和少校不同，很有二下子喔？讓我提起戰鬥興致了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양! 이쪽은 제가 맡을 테니까 어서 가세요! 빨리요!","JPN":"カリンさん！　こちらは任せて行ってください！　早く！","ENG":"Karin! Leave this to me! You go ahead! Hurry!","TWN":"卡琳！這邊交給我，去做你的事！快點！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뒤는 맡기겠습니다!","JPN":"後は頼みます！","ENG":"Thank you!","TWN":"後面就拜託你了！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"뭐라는 거야! 누가 순순히 보내줄 것……","JPN":"何言ってんだよ！　誰が行かせるって……","ENG":"What?! I'm not gonna just let you–","TWN":"說什麼呢！別想就這麼跑……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"읏!","JPN":"うっ！","ENG":"Ngh!","TWN":"唔！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"글쎄? 순순히 보내줄 수밖에 없을 걸?","JPN":"どうかな？　行かせる以外に手はないと思うよ？","ENG":"Oh really? I think you are just gonna let her go that easily.","TWN":"是嗎？你還是乖乖地在這裡看著吧？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"오랜만에 꽤 진심으로 해볼 생각이 들었거든.","JPN":"久しぶりに本気出しちゃおうかと思っているからね。","ENG":"I haven't fought seriously in a long time, but I'm excited now.","TWN":"真是好久沒有那麼認真了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"박사님! 포인트를 재확보하였습니다!","JPN":"博士！　ポイントを再確保しました！","ENG":"Doctor! I've re-secured my position!","TWN":"博士！我重新回到了狙擊點！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"차원 통로는! 차원 통로는 어떻게 되었죠!?","JPN":"次元通路は！　次元通路はどうなっていますか！？","ENG":"The dimensional passage! What happened to it?!","TWN":"次元通道呢！次元通道怎麼樣了？！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L29_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"늦었어. 차원통로는 소멸했어. 작전은 실패야.","JPN":"もう遅い。次元通路は消滅した。作戦失敗だ。","ENG":"It's too late. The dimensional passage is gone. This operation is a failure.","TWN":"太晚了，次元通道已經消失了，作戰失敗了。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이, 이럴 수가……!","JPN":"そ、そんな……！","ENG":"I-it can't be...!","TWN":"怎，怎麼會……！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"또야, 또 나 때문이야……!","JPN":"まただ、また私のせいで……！","ENG":"Again... It's my fault again...!","TWN":"又，又是因為我……！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"내가, 내가 타이밍을 맞추지 못해서! 나 때문에 부관님이!","JPN":"私が、私が間に合わなかったから！　私のせいで副官が！","ENG":"It's... it's because I couldn't get the timing right! It's my fault that Adjutant Kropel is...!","TWN":"是我，是我沒能把握時機！是我害副官！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"자책하지 마, 소령.","JPN":"自分を責めるな、少佐。","ENG":"Don't beat yourself up too much, Major.","TWN":"沒必要這麼自責，少校。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"부관이 떨어진 차원은 통로가 1분도 유지되지 못할 정도로 불안정한 곳이었어.","JPN":"副官が落ちた次元は通路が1分も持たないぐらい不安定なところだった。","ENG":"The dimensional passage she went through was too unstable that it didn't even last for a minute.","TWN":"副官所在的次元很不穩定，通道連1分鐘都無法維持。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"어차피 소령이 저격을 시도했어도…… 타이밍을 맞추지 못했을 거야.","JPN":"仮に少佐が狙撃を行ったとしても……タイミングを合わせるのは不可能だっただろう。","ENG":"Even if you did attempt to shoot... The timing wouldn't have worked.","TWN":"就算少校有能力進行狙擊……也無法趕上正確的時機。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그럼, 제이나 부관님은……?","JPN":"それでは、ジェイナ副官は……？","ENG":"Then, what about Adjutant Kropel...?","TWN":"那麼，婕娜副官……？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"죽었겠지. 아마도.","JPN":"死んだだろうな。おそらく。","ENG":"She's dead. Probably.","TWN":"大概是死了。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"그럼, 내가 기적을 만들었을 때, 놓치지 말고 저격이나 잘하도록.","JPN":"なら、私が奇跡を作り出した瞬間に確実に狙撃しなさい。","ENG":"Then, when I make the miracle happen, make sure not to miss your shot.","TWN":"那麼，我創造奇蹟的時候，好好看著別錯過。"},"stage":{"bg":"PROLOGUE_02","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L44_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"기회는 단 한번뿐이니까.","JPN":"チャンスは一度しかないわ。","ENG":"We only have one shot at this.","TWN":"畢竟機會只有一次。"},"stage":{"bg":"PROLOGUE_02","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"소령? 카린 웡 소령! 뭐하는 거야!","JPN":"少佐！　カリン・ウォン少佐！　何をする気だ！","ENG":"Major? Major Wong! What are you doing?!","TWN":"少校？卡琳少校！你在做什麼！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"현 시간부로 작전을 플랜B로 전환!","JPN":"現時刻より作戦をプランBに切り替える！","ENG":"From this point on, we move on to plan B!","TWN":"即刻起作戰改為B計畫！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이대로 아포리아가 핵을 노출하는 순간을 노려서 저격하겠습니다!","JPN":"このままアポリアの核が剥き出しになる瞬間を狙って狙撃します！","ENG":"I'll shoot Aporia's core when it's exposed!","TWN":"我會瞄準阿波利亞露出核心的瞬間進行狙擊！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"무슨 소리야! 그건 1차 공략 작전에서도 실패했던 거잖아!","JPN":"何を言っているんだ！　それは最初の作戦でも失敗しただろう！","ENG":"Are you serious?! That's what we tried last time and it failed!","TWN":"你在說什麼！那個計畫第一次作戰時就失敗了！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"하지만 마음에 들었어.","JPN":"でも、私は気に入ったわ。","ENG":"But I like it.","TWN":"不過我很滿意。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L6_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"그 괴물한테 한 방 먹여주고 싶은 건 너희만이 아니거든.","JPN":"あの化け物に一発食らわせてやりたいのは、あなたたちだけじゃないのよ。","ENG":"You're not the only one who wants to take that monster down.","TWN":"想狠狠給那怪物一拳的不是只有你們。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그럼, 그 외에 다른 방법이 있나요!?","JPN":"じゃあ、他に方法があるんですか？","ENG":"Then what other plans do we have?!","TWN":"那麼，還有其他辦法嗎？！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는…… 저는 반드시 이 아티팩트로 아포리아를 저격해야만 합니다……!","JPN":"私は……私は絶対にこのアーティファクトでアポリアを狙撃しなければなりません……！","ENG":"I... I must use this Artifact to shoot Aporia...!","TWN":"我，我……一定讓這個人造神器射中阿波利亞……！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그것이 스스로를 희생한 부관님의 의지를 헛되이 하지 않는 유일한 방법이니까요!","JPN":"それが自らを犠牲にした副官の意志を無駄にしない、唯一の方法ですから！","ENG":"This is the only way Adjutant Kropel's sacrifice does not end in vain!","TWN":"這才不會讓副官白白犧牲！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"반드시! 반드시 성공시킬 겁니다!","JPN":"絶対に！　絶対に成功させます！","ENG":"It must work! I will make it work!","TWN":"我一定！一定要成功！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그만두게, 소령!","JPN":"やめておけ、少佐！","ENG":"Stop, Major!","TWN":"住手，少校！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"닥치세요!! 안토노프!!","JPN":"黙ってください！！　アントノフ！！","ENG":"Be quiet!! Antonov!!","TWN":"給我閉嘴！！安東諾夫！！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"왜 이따위 짓을 벌인 겁니까!!","JPN":"なんでこんなことをしたんですか！！","ENG":"Why did you do this?!","TWN":"你為什麼這麼做！！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리를 도와주지도 않을 거면서, 대체 왜 방해한 거냐고!!","JPN":"助けてくれるわけでもないのに、なんで邪魔ばかりするの！！","ENG":"I knew you weren't going to help us, but why interfere with our operation?!","TWN":"既然不幫忙，為什麼又要阻礙我們！！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"왜냐고? 그 아티팩트는 고출력 빔 병기 같은 게 아니니까!","JPN":"何でかって？　そのアーティファクトは高出力ビーム兵器なんかじゃないからだ！","ENG":"Why? Because that Artifact is not a high-powered beam weapon!","TWN":"為什麼？因為那個人造神器不是高輸出電波武器！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 아티팩트는 고출력 좌표 신호기. 일명, <color=#ffd34c>등대</color>라는 물건이야!!","JPN":"そのアーティファクトは高出力座標信号機。その名も、<color=#ffd34c>灯台</color>！！","ENG":"That Artifact is a high-powered coordinate signaler. The <color=#ffd34c>Lighthouse</color> is another name for it!!","TWN":"那個人造神器是高輸出座標信號器，又稱為<color=#ffd34c>燈塔</color>！！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그걸 작동시키는 순간, 수십 킬로 반경의 모든 침식체들이 방위선으로 몰려들걸세!!","JPN":"それを作動させた途端、半径数十キロ内にいるあらゆる侵食体が防衛線に集まってきてしまう！！","ENG":"The second you activate that, all C.O.s within its radius will rush to the Defense Line!","TWN":"啟動它的瞬間，數十公里半徑內的所有侵蝕體都會湧向防線！！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그건 자네도 바라지 않는 일 아닌가!!","JPN":"君もそれを望んでいるわけじゃないだろう！！","ENG":"And I know you do not want that to happen!!","TWN":"你也不想讓那種事發生吧！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"닥치라고 했습니다!! 먼저 기습해놓고 그따위 말장난에 속을 것 같아!?","JPN":"黙れと言いました！！　そちらから先に奇襲をかけておいて、そんな適当な話に騙されると思いますか！！","ENG":"I told you to shut up!! You think I'm a fool to believe a word you say after you ambushed us?!","TWN":"我叫你閉嘴！！先是跑來偷襲，再用這種玩笑一樣的話欺騙我？當我是傻子嗎！！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"속이는 게 아니야! 우리 입장에서도 그 아티팩트는 앞으로의 항해에 중요한 물건이야!","JPN":"騙しているんじゃない！　我々にとってもそのアーティファクトがこれからの航海に必要なんだ！","ENG":"I am not fooling you! This Artifact is a crucial component for our upcoming voyage!","TWN":"這不是欺騙！對於我們來說，那件人造神器是以後航行的重要物件！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"우연이지만, 그걸 발견해버린 이상 이런 곳에서 무의미하게 소모하게 둘 수 없어!","JPN":"偶然だが、見つけてしまったからには、こんなところで無意味に消耗させるわけにはいかない！","ENG":"It may be a coincidence, but as long as it has been discovered, I cannot allow you to use it meaninglessly!","TWN":"雖然是碰巧發現的，但既然碰到了，就不能讓它在這裡無意義地被消耗！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"무의미…… 하다고……?","JPN":"無意味……ですって……？","ENG":"You said… meaninglessly...?","TWN":"無意義……嗎……？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그래! 이제 알겠어! 당신에게는 무의미할지도 모르겠지!","JPN":"ええ！　そうよね！　あなたには無意味かもしれないわ！","ENG":"Fine! I get it now! This may all be meaningless to you!","TWN":"好！我明白了！也許對你來說沒有意義！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어차피 당신은 엑자일러니까! 당신은 그저 우리 세계를 발판 정도로 생각하고 있잖아!","JPN":"所詮あなたはエグザイラー！　私たちの世界を踏み台程度にしか考えてないのよ！","ENG":"After all, you're just an Exile! You think of our worlds as nothing but a stepping stone!","TWN":"反正你是個流浪者！我們的世界不過是你的跳板而已！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 우리는 아니야!","JPN":"でも、私たちは違う！","ENG":"But we do not!","TWN":"但對我們來說不是！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"살아 남기 위해, 세계를 살리기 위해! 최선을 다하고 있어!","JPN":"生き残るために、世界を救うために！　全力を尽くしているの！","ENG":"We're doing our best! To survive! To save this world!","TWN":"為了活下去，為了拯救世界！我們可是拚了命在努力！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까 이방인 따위가 우리 세계의 일에 참견할 권한은 없다고!","JPN":"他所の人間に、この世界について口出しされる筋合いなんかないわ！","ENG":"So an outsider like you has no right to intervene in our affairs!","TWN":"你這種外邦人沒有權利干涉我們世界的事情！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"말이 안 통하는군.","JPN":"話が通じないな。","ENG":"I see this is going nowhere.","TWN":"看來目前無法和你溝通。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"카린 웡!! 목표를 저격하겠습니다!!","JPN":"カリン・ウォン！！　ターゲットを狙撃します！！","ENG":"Karin Wong!! Aiming for the target!!","TWN":"卡琳！！狙擊目標！！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아티팩트가 작동하지 않았어. 방금 포격으로 발전소와의 연결을 끊어버린 건가?","JPN":"アーティファクトが作動しない。今の砲撃で発電所とのコネクトを切られた？","ENG":"The Artifact didn't activate. Was the power cut off from the generator by that blast?","TWN":"人造神器沒有啟動，剛剛的炮擊將它與發電站的連接切斷了嗎？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇다는 건…….","JPN":"ということは……","ENG":"That means...","TWN":"那也就是說……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"제4 방위선에 있는 모든 인원은 고개를 들어 하늘을 올려 보도록!","JPN":"第4防衛線にいるすべての者は上空を見よ！","ENG":"Everyone at the 4th Defense Line! Look up at the sky!","TWN":"第四防線的全體人員，抬頭看向天空！"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"나는 이 세계에 존재하는 유일한 차원 함선, 아이기스의 함장 안토노프 사령관이다.","JPN":"私はこの世界に存在する唯一の次元艦船、アイギスの艦長であるアントノフ司令官だ。","ENG":"I am Commander Antonov, captain of Aegis, this world's only dimensional ship.","TWN":"我是這個世界上唯一一艘次元艦船，埃癸斯的艦長安東諾夫司令官。"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"동시에 다른 세계로부터 정착한 엑자일러이기도 하지.","JPN":"また、他の世界から来て定着したエグザイラーでもある。","ENG":"At the same time, I am an Exile from another world.","TWN":"同時也是來自其他世界的流浪者。"},"stage":{"bg":"SKY_SUNSET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"단도직입적으로 말하겠다.","JPN":"単刀直入に言おう。","ENG":"I will be honest with you all.","TWN":"我就直接了當地說了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"다들 알다시피, 이 세계는 피할 수 없는 멸망에 직면해 있다.","JPN":"皆も知っているとおり、この世界は逃れられない滅亡に直面している。","ENG":"As you are all aware, this world is facing inevitable destruction.","TWN":"正如大家所知，這個世界面臨著不可避免的滅亡。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그리고 나는 이곳을 떠나, 다른 세계에 정착할 수 있는 기술과 함선을 보유하고 있다.","JPN":"そして私はここを離れ、他の世界に定着することのできるテクノロジーと艦船を持っている。","ENG":"I have the ship and technology to leave this world and settle in another one.","TWN":"我有能離開這個地方，去往其他世界定居的技術和艦船。"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"따라서 내가 자네들의 구원자가 되어주지.","JPN":"よって、私が君たちの救世主となろう。","ENG":"So I shall be your savior.","TWN":"我能拯救你們。"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"자네들 중 싸울 수 있는 자, 전문 지식을 지닌 자, 물자를 제공할 수 있는 자……","JPN":"君たちの中で、戦える者、専門知識を有する者、物資の提供が可能な者……","ENG":"Those who can fight, have expertise, or provide materials...","TWN":"你們當中，有專職戰鬥的人，有身具專業知識的人，有可以提供物資的人……"},"stage":{"bg":"PROLOGUE_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 밖에 자신의 가치를 증명할 수 있는 모든 이들은 내가 있는 제3 방위선으로 오도록!","JPN":"その他、自分の価値を証明できるすべての者は第3防衛線まで来たまえ！","ENG":"And all others who can prove their worth! Come to me at the 3rd Defense Line!","TWN":"所有能證明自身價值的人，與我前往第三防線！"},"stage":{"bg":"PROLOGUE_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"내게 자격을 인정받는 인원은 특별히 내 이주 플랜에 동참할 기회를 주도록 하지.","JPN":"そこで私に能力を認められた者は、特別に我が移住計画に参加するチャンスを与える。","ENG":"Those whom I see fit, I shall give them the opportunity to join my emigration plan!","TWN":"那些得到我認可的人員，我將特准你們參與我的移居計畫！"},"stage":{"bg":"PROLOGUE_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"어차피 멸망할 세계를 위해 끝까지 싸우다가 죽을 것인지.","JPN":"どのみち滅亡する世界のために、最後まで戦って死ぬか。","ENG":"Whether you fight to save a crumbling world.","TWN":"是要為了瀕臨滅亡的世界而戰鬥到底。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"세계를 버리더라도 다 같이 살아남을 것인지.","JPN":"あるいは世界を捨ててでも、みんなで生き残るか。","ENG":"Or save yourself and abandon your home.","TWN":"還是放棄這個世界，一起活下去。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"선택은 자네들의 몫이다.","JPN":"選択は君たちに任せる。","ENG":"The choice is yours.","TWN":"選擇權在你們的手上。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"안토노프.","JPN":"アントノフ。","ENG":"Antonov.","TWN":"安東諾夫。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이렇게 나온다 이거지?","JPN":"そう来るなら、こっちにも考えがあるわ。","ENG":"So this is how you're going to be.","TWN":"這就是你的目的吧？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};